func:
// ============================================================
// Locatiebepaling: tijd-gevensterde argmax met hysteresis
// ============================================================
// Per speler houden we per paal recente RSSI-samples (met timestamp) bij.
// Samples ouder dan VENSTER_MS vervallen, zodat een verlaten paal vanzelf
// uit beeld raakt (geen 'kleven' meer aan een oude sterke meting).
// De speler staat bij de paal met het sterkste recente gemiddelde (argmax);
// wisselen gebeurt pas als die duidelijk sterker is dan de huidige paal.

// In simulatiemodus negeert de echte locatiebepaling alle plaatjes/data en
// [TEST]-injects, zodat 'Sim directe locatie' de enige schrijver van
// spelerLocaties is (standalone, geen vervuiling).
if (global.get("simVeld24") === true) return null;

// --- TUNING: live uit global.locParams (defaults veilig) ---
const P = global.get("locParams") || {};
const VENSTER_MS     = P.vensterMs    ?? 6000;
const HYSTERESE_DBM  = P.hystereseDbm ?? 6;
const RSSI_VLOER     = P.rssiVloer    ?? -92;
const GRACE_MS       = P.graceMs      ?? 4000;
const SWITCH_SAMPLES = P.switchSamples ?? 2;
const MIN_SAMPLES    = P.minSamples   ?? 2;
const MAX_SAMPLES    = 80;

// --- 0. SMOELENBOEK ---
const spelersLijst = global.get("spelersLijst") || {};
const ruweMac = msg.payload.mac;
const spelerNaam = spelersLijst[ruweMac];
if (!spelerNaam) return null; // Onbekende beacon negeren
const gepauzeerd = global.get("gespauzeerdePlayers") || {};
if (gepauzeerd[spelerNaam] === true) return null;

const paal = msg.payload.paal;
const kal = (global.get("beaconKalibratie") || {})[ruweMac] || 0;
const rssi = msg.payload.rssi + kal;
const nu = Date.now();
if (rssi < RSSI_VLOER) return null; // te zwak = ruis, niet meetellen

// --- 1. GEHEUGEN ---
let geschiedenis = context.get("geschiedenis") || {};
let spelerLocaties = global.get("spelerLocaties") || {};

if (!geschiedenis[spelerNaam] || !geschiedenis[spelerNaam].samples) {
    geschiedenis[spelerNaam] = { huidigePaal: null, samples: {}, laatstPaal: {}, uitdager: null, uitdagerTeller: 0 };
}
let g = geschiedenis[spelerNaam];
if (!g.laatstPaal) g.laatstPaal = {};

// --- 2. NIEUWE SAMPLE + PRUNE ---
if (!g.samples[paal]) g.samples[paal] = [];
g.samples[paal].push({ rssi: rssi, ts: nu });
g.laatstPaal[paal] = nu;

for (const p in g.samples) {
    // verouderde samples weggooien
    g.samples[p] = g.samples[p].filter(s => (nu - s.ts) <= VENSTER_MS);
    // lengte begrenzen (laatste MAX_SAMPLES houden)
    if (g.samples[p].length > MAX_SAMPLES) {
        g.samples[p] = g.samples[p].slice(-MAX_SAMPLES);
    }
    // lege palen verwijderen zodat ze geen kandidaat meer zijn
    if (g.samples[p].length === 0) delete g.samples[p];
}

// --- 3. MEDIAAN RSSI PER PAAL (robuust tegen uitschieters) ---
function mediaan(arr) {
    const a = arr.map(s => s.rssi).sort((x, y) => x - y);
    const m = a.length >> 1;
    return a.length % 2 ? a[m] : (a[m - 1] + a[m]) / 2;
}
let med = {};
for (const p in g.samples) {
    if (g.samples[p].length >= MIN_SAMPLES) med[p] = mediaan(g.samples[p]);
}

// --- 4. ARGMAX kandidaat (sterkste mediaan) ---
let bestePaal = null;
let besteRssi = -Infinity;
for (const p in med) {
    if (med[p] > besteRssi) { besteRssi = med[p]; bestePaal = parseInt(p, 10); }
}

// --- 5. BESLISSING: grace + sustained-switch ---
const vorigePaal = g.huidigePaal;
if (bestePaal !== null) {
    if (vorigePaal === null || vorigePaal === undefined) {
        g.huidigePaal = bestePaal; g.uitdager = null; g.uitdagerTeller = 0;
    } else {
        const huidigeHeeftData = (vorigePaal in med);
        const stilMs = nu - (g.laatstPaal[vorigePaal] || 0);
        if (!huidigeHeeftData) {
            // huidige paal stil: vasthouden binnen grace, daarna pas loslaten
            if (stilMs > GRACE_MS) { g.huidigePaal = bestePaal; g.uitdager = null; g.uitdagerTeller = 0; }
        } else if (bestePaal !== vorigePaal && med[bestePaal] >= med[vorigePaal] + HYSTERESE_DBM) {
            // uitdager duidelijk sterker -> moet SWITCH_SAMPLES keer leiden
            if (g.uitdager === bestePaal) g.uitdagerTeller++; else { g.uitdager = bestePaal; g.uitdagerTeller = 1; }
            if (g.uitdagerTeller >= SWITCH_SAMPLES) { g.huidigePaal = bestePaal; g.uitdager = null; g.uitdagerTeller = 0; }
        } else {
            g.uitdager = null; g.uitdagerTeller = 0;
        }
    }
}

// Beweging-event ALLEEN bij een echte wissel (niet bij eerste lokalisatie),
// zodat het puntensysteem geen levensuur toekent op de allereerste detectie.
let bewegingEvent = null;
if (g.huidigePaal !== vorigePaal &&
    vorigePaal !== null && vorigePaal !== undefined) {
    bewegingEvent = { payload: { speler: spelerNaam, vanPaal: vorigePaal, naarPaal: g.huidigePaal } };
}

context.set("geschiedenis", geschiedenis);

// --- 6. CENTRALE WAARHEID ---
if (g.huidigePaal !== null && g.huidigePaal !== undefined) {
    spelerLocaties[spelerNaam] = g.huidigePaal;
    global.set("spelerLocaties", spelerLocaties);
}

// --- 7. TABELDATA (incl. levensuren/levensdagen uit flow 04) ---
const stats = global.get("spelerStats") || {};
let tabelData = [];
for (let speler in spelerLocaties) {
    const totaalUren = (stats[speler] && stats[speler].totaalUren) || 0;
    const huidige = spelerLocaties[speler];
    // toon de mediaan-RSSI over het venster voor de actieve paal
    let rssiTekst = "?";
    const sg = geschiedenis[speler] && geschiedenis[speler].samples;
    if (sg && sg[huidige] && sg[huidige].length) {
        rssiTekst = Math.round(mediaan(sg[huidige]));
    }
    tabelData.push({
        "Speler": speler,
        "Locatie": "Paal " + huidige,
        "RSSI": rssiTekst,
        "Levensdagen": Math.floor(totaalUren / 24),
        "Levensuren": totaalUren % 24,
        "Sterftes": (stats[speler] && stats[speler].sterftes) || 0
    });
}

msg.payload = tabelData;
// Output 1: radar-tabel  |  Output 2: beweging-event naar puntensysteem
return [msg, bewegingEvent];

// Detectie binnen via plaatjes/data: {paal, mac, rssi}
const nu = Date.now();
const d = msg.payload;
if (!d || d.paal === undefined || !d.mac) { return null; }

let macSeen = global.get("status_lastSeenMac") || {};
let paalSeen = global.get("status_lastSeenPaal") || {};

macSeen[d.mac] = nu;
paalSeen[d.paal] = nu;

global.set("status_lastSeenMac", macSeen);
global.set("status_lastSeenPaal", paalSeen);
global.set("status_lastDataTs", nu);

return msg;

// Pre-flight check: deze evaluatie loopt CONTINU (elke ~1s), óók als het spel gestopt of
// gepauzeerd is — de bron-data (laatst gezien per speler/paal, datastroom, batterij) wordt los
// van de spel-toestand bijgewerkt, zodat je de veld-status altijd kunt aflezen voor de start.
// === Spelstatus evaluatie ===
const nu = Date.now();

// Instelbare drempels
const SPELER_TIMEOUT_MS = 15000;
const SLAVE_STALE_MS = 60000;
const GEEN_DATA_MS = 10000;

// Bronnen
const spelersLijst = global.get("spelersLijst") || {};
const paaltjesLijst = global.get("paaltjesLijst") || [];
const macSeen = global.get("status_lastSeenMac") || {};
const paalSeen = global.get("status_lastSeenPaal") || {};
const lastDataTs = global.get("status_lastDataTs") || 0;
const batterijPaal = global.get("status_batterijPaal") || {};
const toonBatterij = global.get("status_toonBatterij") === true;
const override = global.get("status_override") === true;

// In simulatiemodus alleen actieve (niet-verwijderde) spelers evalueren
const _sim = global.get("simVeld24") === true;
const _locAanwezig = global.get("spelerLocaties") || {};

let fouten = [];

// 1. SPELERS
let spelersTabel = [];
for (const mac in spelersLijst) {
    const naam = spelersLijst[mac];
    if (_sim && !(naam in _locAanwezig)) continue;
    const t = macSeen[mac];
    let status, ouderdom;
    if (!t) {
        status = "NIET GEZIEN";
        ouderdom = "-";
        fouten.push({ Code: "ST-001", Niveau: "FOUT", Onderdeel: naam, Omschrijving: "Speler nog niet gedetecteerd in het veld" });
    } else if (nu - t > SPELER_TIMEOUT_MS) {
        ouderdom = (nu - t > 300000) ? ">300s" : Math.round((nu - t) / 1000) + "s";
        status = "VERLOREN";
        fouten.push({ Code: "ST-001", Niveau: "FOUT", Onderdeel: naam, Omschrijving: "Speler al " + ouderdom + " niet meer gezien" });
    } else {
        ouderdom = (nu - t > 300000) ? ">300s" : Math.round((nu - t) / 1000) + "s";
        status = "OK";
    }
    spelersTabel.push({ Speler: naam, Status: status, "Laatst gezien": ouderdom });
}

// 2. SLAVES / PALEN
let palenTabel = [];
for (const paal of paaltjesLijst) {
    const t = paalSeen[paal];
    let status, ouderdom;
    if (!t) {
        status = "GEEN CONTACT";
        ouderdom = "-";
        fouten.push({ Code: "ST-002", Niveau: "WAARSCHUWING", Onderdeel: "Paal " + paal, Omschrijving: "Slave heeft nog geen data gestuurd" });
    } else if (nu - t > SLAVE_STALE_MS) {
        ouderdom = (nu - t > 300000) ? ">300s" : Math.round((nu - t) / 1000) + "s";
        status = "VEROUDERD";
        fouten.push({ Code: "ST-002", Niveau: "WAARSCHUWING", Onderdeel: "Paal " + paal, Omschrijving: "Slave al " + ouderdom + " stil" });
    } else {
        ouderdom = (nu - t > 300000) ? ">300s" : Math.round((nu - t) / 1000) + "s";
        status = "OK";
    }
    // Batterij-kolom: gevuld als toggle aan staat, anders "-"
    let batterijTekst = "-";
    if (toonBatterij) {
        const b = batterijPaal[paal];
        batterijTekst = (b && typeof b.volt === "number")
            ? b.volt.toFixed(2) + " V"
            : "?";
    }
    palenTabel.push({ Paal: paal, Status: status, "Laatst gezien": ouderdom, "Batterij": batterijTekst });
}

// 3. DATASTROOM
if (lastDataTs === 0) {
    fouten.push({ Code: "ST-003", Niveau: "FOUT", Onderdeel: "Datastroom", Omschrijving: "Nog geen enkel bericht ontvangen op plaatjes/data" });
} else if (nu - lastDataTs > GEEN_DATA_MS) {
    fouten.push({ Code: "ST-003", Niveau: "FOUT", Onderdeel: "Datastroom", Omschrijving: "Al " + Math.round((nu - lastDataTs) / 1000) + "s geen data - controleer master/bridge" });
}

// 4. ONBEKENDE BEACONS (informatief)
for (const mac in macSeen) {
    if (!spelersLijst[mac] && (nu - macSeen[mac] < SPELER_TIMEOUT_MS)) {
        fouten.push({ Code: "ST-004", Niveau: "INFO", Onderdeel: mac, Omschrijving: "Onbekende beacon gedetecteerd (niet geregistreerd)" });
    }
}

// SAMENVATTING
const aantalFout = fouten.filter(f => f.Niveau === "FOUT").length;
const spelOk = aantalFout === 0 && spelersTabel.length > 0 && palenTabel.length > 0;

global.set("status_ok", spelOk);
global.set("status_fouten", fouten);

let statusTekst;
if (spelOk) {
    statusTekst = override
        ? "GO - spelstatus OK (override actief)"
        : "GO - spelstatus OK, klaar om te starten";
} else if (override) {
    statusTekst = "NO-GO - " + aantalFout + " fout(en) - OVERRIDE actief, Start spel mogelijk";
} else {
    statusTekst = "NO-GO - " + aantalFout + " fout(en), zie foutcodes";
}

const foutenTabel = fouten.length > 0
    ? fouten
    : [{ Code: "-", Niveau: "INFO", Onderdeel: "-", Omschrijving: "Geen fouten" }];

return [
    { payload: spelersTabel },
    { payload: palenTabel },
    { payload: foutenTabel },
    { payload: statusTekst }
];

// Verwerk een knop van het Bediening-/Simulatie-dashboard
const actie = msg.payload;
let toestand = global.get("spelToestand") || "gestopt";
const statusOk = global.get("status_ok");
const override = global.get("status_override") === true;
let melding = "";

// Reset van de PARTIJ-staat (gedeeld door stop en herstart). De GLOBALE stats
// (totaalUren/levensdagen/sterftes/skills) blijven bewaard — die wis je apart met
// [BEHEER] Wis globale stats.
function resetSpelStaat() {
    const _af = global.get("pofHuidigSpel");
    if (_af && _af.events && _af.events.length) {
        _af.eind = new Date().toISOString();
        const _h = global.get("spelHistorie") || [];
        _h.unshift(_af);
        global.set("spelHistorie", _h);
    }
    global.set("pofHuidigSpel", null);
    global.set("pofHuidigEvent", null);
    global.set("pofWachtrij", []);
    global.set("pofActief", false);
    global.set("pofFase", "idle");
    global.set("pofTeller", 0);
    global.set("pofEventenRonde", 0);
    global.set("pofDoelwitReveal", "");
    global.set("bordStaat", {});
    global.set("spelerEffecten", {});
    global.set("wereldEffecten", []);
    global.set("ziekeSpelers", {});
    global.set("pofGenezen", []);
    global.set("dienaars", {});
    global.set("middernachtOogst", false);
    global.set("middernachtActief", false);
    global.set("pofVerificatie", {});
    global.set("pofLaatsteControle", []);
}

switch (actie) {
    case "start":
        if (toestand === "lopend") {
            melding = "Spel liep al.";
        } else if (statusOk === false && !override) {
            melding = "NO-GO - kan niet starten. Los fouten op of zet OVERRIDE aan.";
        } else {
            toestand = "lopend";
            melding = (statusOk === false && override) ? "Spel GESTART met OVERRIDE - spelstatus was NIET OK" : "Spel gestart.";
        }
        break;
    case "pauzeer":
        if (toestand === "lopend") { toestand = "gepauzeerd"; melding = "Spel gepauzeerd."; }
        else melding = "Pauzeren kan enkel terwijl het spel loopt.";
        break;
    case "hervat":
        if (toestand === "gepauzeerd") { toestand = "lopend"; melding = "Spel hervat."; }
        else melding = "Hervatten kan enkel vanuit pauze.";
        break;
    case "herstart":
        resetSpelStaat();
        toestand = "lopend";
        melding = "Spel herstart - partij teruggezet (globale stats blijven).";
        break;
    case "stop":
        resetSpelStaat();
        toestand = "gestopt";
        melding = "Spel GESTOPT - partij gereset (globale stats blijven).";
        break;
    case "toon":
        melding = "Huidige toestand.";
        break;
    default:
        melding = "Onbekende actie: " + actie;
}

global.set("spelToestand", toestand);

if ((actie === "start" || actie === "herstart") && toestand === "lopend") {
    global.set("pofHuidigSpel", { id: Date.now(), start: new Date().toISOString(), events: [] });
}

msg.payload = "Toestand: " + toestand.toUpperCase() + "  |  " + melding;
// Bij stop/herstart: trigger Ziekte-beheer zodat pof/ziekte (retained) geleegd wordt en de medicijn-LEDs doven.
const zReset = (actie === "stop" || actie === "herstart") ? {} : null;
return [msg, zReset];

// Status-event van de MQTT-in node: bepaal of de broker bereikbaar is.
// node-red zet fill='green' bij 'connected', anders rood/grijs/geel.
const fill = msg.status && msg.status.fill;
const text = (msg.status && msg.status.text) || "";
const connected = (fill === "green")
    || /connected/i.test(text);
return { payload: connected };

// Batterij-regel binnen via plaatjes/data: {paal, batt}
// Tegelijk gebruiken als heartbeat zodat een paal met 0 spelers ook
// als 'levend' geldt in de spelstatus.
const nu = Date.now();
const d = msg.payload;
if (!d || d.paal === undefined || d.batt === undefined) return null;

let batterijPaal = global.get("status_batterijPaal") || {};
batterijPaal[d.paal] = { volt: d.batt, ts: nu };
global.set("status_batterijPaal", batterijPaal);

let paalSeen = global.get("status_lastSeenPaal") || {};
paalSeen[d.paal] = nu;
global.set("status_lastSeenPaal", paalSeen);
global.set("status_lastDataTs", nu);
return null;

// Positie-update + PAD-OPNAME. Levensuren worden niet hier toegekend, maar bij de
// controle (Verifieer beweging) op basis van het opgenomen pad.
const ev = msg.payload;
if (!ev || !ev.speler || ev.vanPaal === undefined || ev.naarPaal === undefined) {
    return null;
}
let stats = global.get("spelerStats") || {};
let s = stats[ev.speler] || {};
if (s.totaalUren === undefined) s.totaalUren = 0;
if (s.sterftes === undefined) s.sterftes = 0;
if (s.tijdTerug === undefined) s.tijdTerug = false;

// Tijdens de bewegingsfase elke settled paalwissel als hop bewaren (geordend pad).
const fase = global.get("pofFase") || "idle";
if (fase === "reactie" || fase === "wacht_controle") {
    let pad = global.get("pofPad") || {};
    (pad[ev.speler] = pad[ev.speler] || []).push([ev.vanPaal, ev.naarPaal]);
    global.set("pofPad", pad);
}

s.huidigePaal = ev.naarPaal;
stats[ev.speler] = s;
global.set("spelerStats", stats);
msg.payload = {
    speler: ev.speler, van: ev.vanPaal, naar: ev.naarPaal,
    totaalUren: s.totaalUren,
    levensdagen: Math.floor(s.totaalUren / 24),
    levensuren: s.totaalUren % 24,
    sterftes: s.sterftes,
    melding: ev.speler + " positie -> paal " + ev.naarPaal + " (scoren bij de controle)"
};
return msg;

// Admin-reset met twee-staps verificatie.
// Stap 1: 'Admin ontgrendelen' moet AAN (global.admin_unlocked).
// Stap 2: een resetknop. Na uitvoeren vergrendelt het paneel weer.
const topic = msg.topic;
const unlocked = global.get("admin_unlocked") === true;

if (!unlocked) {
    msg.payload = "VERGRENDELD - zet eerst 'Admin ontgrendelen' aan (stap 1).";
    return [msg, null];
}

let stats = global.get("spelerStats") || {};
let aantal = 0;
let wat;
let eenheid = "speler(s)";
let triggerZiekte = false;

if (topic === "reset_dagen") {
    for (let naam in stats) {
        const t = stats[naam].totaalUren || 0;
        stats[naam].totaalUren = t % 24;            // dagen weg, uren-rest blijft
        stats[naam].achterstand = 0;
        stats[naam].verplaatstRonde = 0;
        aantal++;
    }
    wat = "Levensdagen";
} else if (topic === "reset_uren") {
    for (let naam in stats) {
        const t = stats[naam].totaalUren || 0;
        stats[naam].totaalUren = Math.floor(t / 24) * 24;  // uren-rest weg, dagen blijven
        stats[naam].achterstand = 0;
        stats[naam].verplaatstRonde = 0;
        aantal++;
    }
    wat = "Levensuren";
} else if (topic === "reset_sterftes") {
    for (let naam in stats) {
        stats[naam].sterftes = 0;
        aantal++;
    }
    wat = "Sterftes";
} else if (topic === "reset_paaleffecten") {
    const bord = global.get("bordStaat") || {};
    aantal = Object.keys(bord).length;
    global.set("bordStaat", {});
    wat = "Paal-effecten"; eenheid = "paal/palen";
} else if (topic === "reset_spelereffecten") {
    const se = global.get("spelerEffecten") || {};
    const we = global.get("wereldEffecten") || [];
    aantal = Object.keys(se).length + we.length;
    global.set("spelerEffecten", {});
    global.set("wereldEffecten", []);
    wat = "Speler- + Wereld-effecten"; eenheid = "effect(en)";
} else if (topic === "reset_spelertoestanden") {
    const se = global.get("spelerEffecten") || {};
    const zk = global.get("ziekeSpelers") || {};
    const dn = global.get("dienaars") || {};
    aantal = Object.keys(se).length + Object.keys(zk).length + Object.keys(dn).length;
    global.set("spelerEffecten", {});
    global.set("ziekeSpelers", {});
    global.set("dienaars", {});
    global.set("pofGenezen", []);
    triggerZiekte = true;   // laat Ziekte-beheer lege pof/ziekte + pof/dienaars publiceren
    wat = "Speler-toestanden (effecten/ziekte/dienaar)"; eenheid = "toestand(en)";
} else if (topic === "reset_alles") {
    // Alle individuele resets in één klik.
    for (let naam in stats) {
        stats[naam].totaalUren = 0;
        stats[naam].achterstand = 0;
        stats[naam].verplaatstRonde = 0;
        stats[naam].sterftes = 0;
        aantal++;
    }
    global.set("bordStaat", {});
    global.set("spelerEffecten", {});
    global.set("wereldEffecten", []);
    global.set("ziekeSpelers", {});
    global.set("dienaars", {});
    global.set("pofGenezen", []);
    triggerZiekte = true;
    wat = "ALLES (levensuren/dagen, sterftes, alle effecten, ziekte, dienaars)";
} else {
    msg.payload = "Onbekende reset-actie: " + topic;
    return [msg, null];
}

global.set("spelerStats", stats);
global.set("admin_unlocked", false);   // automatisch hervergrendelen

msg.payload = wat + " gereset (" + aantal + " " + eenheid + "). Paneel weer vergrendeld.";
return [msg, { payload: false }, triggerZiekte ? {} : null];

// Merge events per categorie zodat de drie config-injects elkaar niet overschrijven.
const cat = msg.topic;
let all = global.get("pofEvents") || [];
all = all.filter(e => e.categorie !== cat);
if (Array.isArray(msg.payload)) all = all.concat(msg.payload);
global.set("pofEvents", all);
return { topic: "pof/events", payload: all };

// Plates-of-Fate toestandsmachine. Gevoed door de 1s-ticker en de knoppen.
// out1: start CHOOSE | out2: start VERIFY | out3: timer-display | out4: trigger uitvoer
const AANLOOP_S = 5;
const t = msg.topic;
const manueel = global.get("pofManueel") === true;
const lopend = (global.get("spelToestand") || "gestopt") === "lopend";
const disp = (tekst) => ({ payload: tekst });

if (t === "pof_start") {
    global.set("pofActief", true);
    global.set("pofEventenRonde", 0);
    global.set("pofDoelwitDisplay", null);
    if (manueel) {
        global.set("pofFase", "wacht"); global.set("pofTeller", 0);
        return [null, null, disp("Wacht op 'Volgende event'")];
    }
    global.set("pofFase", "aanloop"); global.set("pofTeller", AANLOOP_S);
    return [null, null, disp("Volgend event over: " + AANLOOP_S + "s")];
}
if (t === "pof_stop") {
    global.set("pofActief", false); global.set("pofFase", "idle");
    return [null, null, disp("POF gestopt")];
}
if (t === "pof_volgende") {
    if (global.get("pofActief") === true && lopend && manueel) {
        global.set("pofFase", "bezig");
        return [{ start: true }, null, disp("Event gekozen...")];
    }
    return null;
}
if (t === "pof_controle") {
    // Een klik: de gevolgen zijn na de reveal al uitgevoerd (fase wacht_controle); nu verifieren.
    if (global.get("pofActief") === true && lopend && global.get("pofFase") === "wacht_controle") {
        global.set("pofFase", "bezig");
        return [null, { verify: true }, disp("Controle...")];
    }
    return null;
}

// tick (alleen tijdens een lopend spel met actieve engine)
if (global.get("pofActief") !== true || !lopend) return null;
let fase = global.get("pofFase") || "idle";
let teller = global.get("pofTeller") || 0;

if (fase === "aanloop") {
    teller--;
    if (teller <= 0) { global.set("pofFase", "bezig"); return [{ start: true }, null, disp("Event gekozen...")]; }
    global.set("pofTeller", teller);
    return [null, null, disp("Volgend event over: " + teller + "s")];
}
if (fase === "reactie") {
    teller--;
    if (teller <= 0) { global.set("pofFase", "bezig"); return [null, { verify: true }, disp("Controle...")]; }
    global.set("pofTeller", teller);
    return [null, null, disp("Reactietijd: " + teller + "s")];
}
if (fase === "regroup") {
    // Pauze na een NUKE: spelers hergroeperen; daarna terug naar de normale flow.
    teller--;
    if (teller <= 0) {
        if (manueel) { global.set("pofFase", "wacht"); global.set("pofTeller", 0); return [null, null, disp("Wacht op 'Volgende event'")]; }
        global.set("pofFase", "aanloop"); global.set("pofTeller", AANLOOP_S);
        return [null, null, disp("Volgend event over: " + AANLOOP_S + "s")];
    }
    global.set("pofTeller", teller);
    return [null, null, disp("Regroup: " + teller + "s")];
}
if (fase === "wacht_controle") {
    return [null, null, disp("Wacht op de Controle-knop")];
}
if (fase === "wacht") {
    return [null, null, disp("Wacht op 'Volgende event'")];
}
return null;

// CHOOSE: kies event (met max-limiet), rol getal, kies doelwit en bouw de afroep.
// out1: chain -> Verouder | out2: audio | out3: Huidig event-display | out4: events-teller-display
const events = global.get("pofEvents") || [];
const categorie = msg.categorie || null;
let pool = categorie ? events.filter(e => e.categorie === categorie) : events;

// max-engine: tel actieve toestand-instanties per bron-event (distinct instId) en
// sluit een event uit zolang zijn 'max' bereikt is.
function actieveInstanties(id) {
    const set = new Set();
    const bord = global.get("bordStaat") || {};
    for (const u in bord) for (const e of (bord[u].effecten || [])) if (e.bron === id) set.add(e.instId);
    const se = global.get("spelerEffecten") || {};
    for (const n in se) for (const e of se[n]) if (e.bron === id) set.add(e.instId);
    for (const e of (global.get("wereldEffecten") || [])) if (e.bron === id) set.add(e.instId);
    return set.size;
}
pool = pool.filter(e => (e.max == null) || actieveInstanties(e.id) < e.max);
const _uitgesloten = new Set(global.get("uitgeslotenEvents") || []);
if (_uitgesloten.size) pool = pool.filter(e => !_uitgesloten.has(e.id));
if (!pool.length) { node.warn("Geen kiesbare pofEvents" + (categorie ? " voor " + categorie : "") + " (max bereikt?)"); return null; }

const OPTIE={enkel:[1,1],laag:[1,3],midden:[1,6],hoog:[3,10]};
function rol(o){const r=Array.isArray(o)?o:(OPTIE[o]||[1,1]);return r[0]+Math.floor(Math.random()*(r[1]-r[0]+1));}
function steekproef(arr,n){const k=arr.slice(),u=[];while(u.length<n&&k.length)u.push(k.splice(Math.floor(Math.random()*k.length),1)[0]);return u;}

let _wachtrij = global.get("pofWachtrij") || [];
const _poolIds = new Set(pool.map(e => e.id));
let event = null;
while (_wachtrij.length) { const _id = _wachtrij.shift(); if (_poolIds.has(_id)) { event = pool.find(e => e.id === _id); break; } }
global.set("pofWachtrij", _wachtrij);
if (!event) event = pool[Math.floor(Math.random() * pool.length)];
let tekst = event.tekst;
let getalWaarde = null;
if (event.getal) {
    getalWaarde = rol(event.getal);
    tekst = tekst.replace(/\bx\b/g, getalWaarde);   // vervang losse 'x' door het getal
}
let getalWaarde2 = null;
if (event.getal2) {
    getalWaarde2 = rol(event.getal2);
    tekst = tekst.replace(/\by\b/g, getalWaarde2);   // vervang losse 'y' door het tweede getal (of-keuze)
}

// Doelwit nu al kiezen zodat het AANTAL vooraan in de afroep kan (bv. "3 spelers ...").
const d = event.doelwit || { type: "geen" };
let aantal = (typeof d.aantal === "string") ? rol(d.aantal) : (d.aantal || 1);
let doelwit = [];
if (d.type === "speler") {
    const _loc = global.get("spelerLocaties") || {};
    const _gp = global.get("gespauzeerdePlayers") || {};
    let namen = Object.keys(_loc).filter(n => !_gp[n]);
    if (d.selectie === "alle") { doelwit = namen; }
    else { doelwit = steekproef(namen, aantal); }
} else if (d.type === "uur") {
    let palen = (global.get("palenActief") || global.get("paaltjesLijst") || []).slice();
    if (d.selectie === "alle") { doelwit = palen; }
    else { doelwit = steekproef(palen, aantal); }
} else if (d.type === "groep") {
    // Groep-doelwit: kies een eigenschap-waarde (bv. kleur=rood) en richt het event op ALLE
    // actieve spelers in die groep. Zo is het event minder exclusief bij veel spelers.
    const eig = global.get("spelerEigenschappen") || {};
    const _loc = global.get("spelerLocaties") || {};
    const _gp = global.get("gespauzeerdePlayers") || {};
    const actief = Object.keys(_loc).filter(n => !_gp[n]);
    const veld = (d.veld === "willekeurig" || !d.veld) ? (Math.random() < 0.5 ? "kleur" : "jaar") : d.veld;
    const waarden = [...new Set(actief.map(n => eig[n] && eig[n][veld]).filter(v => v != null))];
    const waarde = d.waarde || (waarden.length ? waarden[Math.floor(Math.random() * waarden.length)] : null);
    doelwit = actief.filter(n => eig[n] && eig[n][veld] === waarde);
    msg.groepVeld = veld; msg.groepWaarde = waarde;
}
msg.doelwit = doelwit;

const huidig = Object.assign({}, event, { tekstIngevuld: tekst, getalWaarde: getalWaarde, getalWaarde2: getalWaarde2, groepVeld: msg.groepVeld, groepWaarde: msg.groepWaarde });
global.set("pofHuidigEvent", huidig);
global.set("pofDoelwitReveal", "");
global.set("pofEventenRonde", (global.get("pofEventenRonde") || 0) + 1);

// Historiek: log dit event in de huidige spel-bundel
let _spel = global.get("pofHuidigSpel");
if (!_spel) { _spel = { id: Date.now(), start: new Date().toISOString(), events: [] }; }
_spel.events.push({ nr: _spel.events.length + 1, tijd: new Date().toISOString(), naam: event.naam, tekst: tekst, getalWaarde: getalWaarde, doelwit: [] });
global.set("pofHuidigSpel", _spel);

msg.event = event;
msg.getalWaarde = getalWaarde;
msg.getalWaarde2 = getalWaarde2;
// Audio-segmenten (knip-en-plak): AANTAL-prefix (getal + zelfst. nw, enkel/meervoud)
// + event-begin + getal + event-eind. De doelwitten zelf worden later afgeroepen.
const _seg = [];
if (d.type === "groep") {
    _seg.push("woorden/een_groep.wav");
} else if (doelwit.length && (d.type === "speler" || d.type === "uur")) {
    _seg.push("getallen/" + doelwit.length + ".wav");
    const enkel = doelwit.length === 1;
    const woord = d.type === "uur" ? (enkel ? "uur" : "uren") : (enkel ? "speler" : "spelers");
    _seg.push("woorden/" + woord + ".wav");
}
if (event.audioVoor) _seg.push("events/" + event.audioVoor);
if (getalWaarde != null) _seg.push("getallen/" + getalWaarde + ".wav");
if (getalWaarde2 != null) { _seg.push("woorden/of.wav"); _seg.push("getallen/" + getalWaarde2 + ".wav"); }
if (event.audioNa) _seg.push("events/" + event.audioNa);
const audio = { payload: { fase: "event", tekst: tekst, segments: _seg, prioriteit: "normaal" } };
const display = { payload: event.naam + " - " + tekst };
const teller = { payload: "Events deze ronde: " + global.get("pofEventenRonde") };
return [msg, audio, display, teller];

// Snapshot beginposities + bouw de doelwit-reveal-audio.
// Het doelwit is al gekozen in "Kies event" (msg.doelwit) zodat het aantal vooraan kan.
const event = msg.event;
const d = event.doelwit || { type: "geen" };
const doelwit = msg.doelwit || [];

// Historiek: vul de doelwitten aan op het laatst gelogde event
let _spelH = global.get("pofHuidigSpel");
if (_spelH && _spelH.events.length) { _spelH.events[_spelH.events.length - 1].doelwit = doelwit.slice(); global.set("pofHuidigSpel", _spelH); }

// Snapshot beginposities van de ACTIEVE spelers (niet-doelwit moet stil blijven).
const loc = global.get("spelerLocaties") || {};
const _gpSnap = global.get("gespauzeerdePlayers") || {};
let startPosities = {};
for (const naam in loc) { if (!_gpSnap[naam]) startPosities[naam] = loc[naam]; }
global.set("pofVerificatie", {
    voorwaarde: event.voorwaarde || "geen",
    getal: msg.getalWaarde,
    getal2: msg.getalWaarde2,
    groepVeld: msg.groepVeld,
    groepWaarde: msg.groepWaarde,
    doelwit: doelwit,
    startPosities: startPosities
});
msg.groepLabel = msg.groepVeld ? (msg.groepVeld + ": " + msg.groepWaarde) : null;
global.set("pofPad", {});   // pad-opname leegmaken voor deze ronde

let tekst;
if (d.type === "groep") tekst = "Groep " + (msg.groepLabel || "?") + ".";
else if (!doelwit.length) tekst = "Dit raakt niemand in het bijzonder.";
else if (d.type === "uur") tekst = "Getroffen uren: " + doelwit.join(", ") + ".";
else tekst = "Getroffen spelers: " + doelwit.join(", ") + ".";
function _veilig(s){return String(s).toLowerCase().replace(/[^a-z0-9]+/g,"_");}
const _segD = ["doelwit/voor.wav"];
if (d.type === "groep") { _segD.push("woorden/" + msg.groepVeld + ".wav"); _segD.push("groepen/" + _veilig(msg.groepWaarde) + ".wav"); }
else for (const _t of doelwit) _segD.push(d.type === "uur" ? "uren/" + _t + ".wav" : "spelers/" + _veilig(_t) + ".wav");
_segD.push("doelwit/na.wav");
const audio = { payload: { fase: "doelwit", tekst: tekst, segments: _segD, prioriteit: "normaal" } };
global.set("pofDoelwitReveal", "");
return [msg, audio];

// Voer gevolgen uit (commando/score/effect/geen). Start daarna de reactietijd.
const event = msg.event;
const doelwit = msg.doelwit || [];
const gevolgen = event.gevolgen || [];
let stats = global.get("spelerStats") || {};
let bord = global.get("bordStaat") || {};
let se = global.get("spelerEffecten") || {};
let we = global.get("wereldEffecten") || [];
function doelUren(){ if(event.doelwit&&event.doelwit.type==="uur")return doelwit;
  if(event.doelwit&&event.doelwit.type==="speler")return doelwit.map(n=>stats[n]&&stats[n].huidigePaal).filter(p=>p!=null); return []; }
let nextId = Date.now();
// instId: 1 instantie per event-afvuring (zo telt een portaal van 2 palen als EEN toestand voor de max-engine).
const instId = "i" + Date.now() + "_" + Math.floor(Math.random()*1000);
function rolDuur(o){const T={kort:[2,4],middel:[4,7],lang:[7,12]};const r=T[o]||[1,1];return r[0]+Math.floor(Math.random()*(r[1]-r[0]+1));}
// duratie op event-niveau: vast getal, [min,max]-bereik (willekeurig), of preset-string.
function rolDuratie(d){ if(Array.isArray(d)){const a=Number(d[0])||1,b=Number(d[1])||a,lo=Math.min(a,b),hi=Math.max(a,b);return lo+Math.floor(Math.random()*(hi-lo+1));} if(typeof d==="string")return rolDuur(d); return Number(d)||1; }
function maakEffect(g, rondes){ return {id:"fx"+(nextId++), bron:(event&&event.id), instId:instId, effect:g.effect, naam:g.naam||(event&&event.tag)||g.effect, resterendeRondes:rondes, data:Object.assign({}, g.data||{})}; }

let commandos = [];
let nukeNu = false;
for (const g of gevolgen) {
  if (g.type === "commando") { for (const p of doelUren()) commandos.push({ payload: { paal: p, actie: g.actie } }); }
  else if (g.type === "score") { for (const n of doelwit){ let s=stats[n]||{totaalUren:0}; if(s.totaalUren===undefined)s.totaalUren=0; s.totaalUren=Math.max(0,s.totaalUren+(g.delta||0)); stats[n]=s; } }
  else if (g.type === "effect") {
     const rondes = (event && event.duratie != null) ? rolDuratie(event.duratie) : ((typeof g.duurRondes === "string") ? rolDuur(g.duurRondes) : (g.duurRondes||1));
     if (g.niveau==="wereld") we.push(maakEffect(g, rondes));
     else if (g.niveau==="speler") for(const n of doelwit){(se[n]=se[n]||[]).push(maakEffect(g, rondes));}
     else if (g.niveau==="uur") { const uren=doelUren(); for(const u of uren){ const fx=maakEffect(g, rondes); const others=uren.filter(x=>x!==u); fx.data.partner=(others.length===1?others[0]:others); bord[u]=bord[u]||{effecten:[]}; bord[u].effecten.push(fx);} }
     else node.warn("effect zonder geldig niveau");
  }
  else if (g.type === "ziekte") {
     // Maak de doelwit-spelers ziek (rondesOver = duratie) en plaats medicijn op evenveel VRIJE uren.
     let ziek = global.get("ziekeSpelers") || {};
     const over = (event && event.duratie != null) ? event.duratie : 10;
     for (const n of doelwit) ziek[n] = over;
     global.set("ziekeSpelers", ziek);
     const palen = (global.get("palenActief") || global.get("paaltjesLijst") || []).slice();
     const bezet = new Set(Object.values(global.get("spelerLocaties") || {}));
     const vrij = palen.filter(u => !(((bord[u] || {}).effecten) || []).length && !bezet.has(u));
     for (let i = vrij.length - 1; i > 0; i--) { const j = Math.floor(Math.random()*(i+1)); const t = vrij[i]; vrij[i] = vrij[j]; vrij[j] = t; }
     for (const u of vrij.slice(0, doelwit.length)) { const fx = maakEffect({ effect: "medicijn", naam: "Medicijn" }, 9999); bord[u] = bord[u] || { effecten: [] }; bord[u].effecten.push(fx); }
  }
  else if (g.type === "nuke") { global.set("nukeActief", true); global.set("paalLedForceRebuild", true); nukeNu = true; /* ontploffing bij de controle */ }
  else if (g.type === "geen") { /* geen neveneffect */ }
  else node.warn("Onbekend gevolg-type: " + g.type);
}
global.set("spelerStats",stats); global.set("bordStaat",bord); global.set("spelerEffecten",se); global.set("wereldEffecten",we);

// Start de reactietijd (zichtbaar afgeteld door de Engine tick). events_sneller halveert.
let reactie = event.reactietijd_s || 10;
if (we.some(e => e.effect === "events_sneller")) reactie = Math.max(1, Math.round(reactie/2));
// In manueel-modus wachten we op de Controle-knop i.p.v. automatisch af te tellen.
if (global.get("pofManueel") === true) {
    global.set("pofFase", "wacht_controle");
    global.set("pofTeller", 0);
} else {
    global.set("pofFase", "reactie");
    global.set("pofTeller", reactie);
}

return [commandos, nukeNu ? {} : null];

// Tel alle blijvende effecten één ronde af; verwijder afgelopen effecten.
// out1: chain -> Kies doelwit | out2: trigger -> Bouw effecten-tabel
function veroud(arr) {
    return (arr || [])
        .map(e => e.effect === "medicijn" ? e : Object.assign({}, e, { resterendeRondes: e.resterendeRondes - 1 }))
        .filter(e => e.resterendeRondes > 0);
}

let bord = global.get("bordStaat") || {};
for (const uur in bord) {
    bord[uur].effecten = veroud(bord[uur].effecten);
    if (!bord[uur].effecten.length) delete bord[uur];
}
global.set("bordStaat", bord);

let se = global.get("spelerEffecten") || {};
for (const naam in se) {
    se[naam] = veroud(se[naam]);
    if (!se[naam].length) delete se[naam];
}
global.set("spelerEffecten", se);

global.set("wereldEffecten", veroud(global.get("wereldEffecten")));

return [msg, { payload: "rebuild" }];

// Plat de drie effect-registers tot tabelrijen voor de Live Radar.
let rijen = [];
const bord = global.get("bordStaat") || {};
for (const uur in bord) {
    for (const e of bord[uur].effecten) {
        rijen.push({ Niveau: "uur", Doel: "Paal " + uur, Effect: e.naam, "Rondes resterend": e.resterendeRondes });
    }
}
const se = global.get("spelerEffecten") || {};
for (const naam in se) {
    for (const e of se[naam]) {
        rijen.push({ Niveau: "speler", Doel: naam, Effect: e.naam, "Rondes resterend": e.resterendeRondes });
    }
}
for (const e of (global.get("wereldEffecten") || [])) {
    rijen.push({ Niveau: "wereld", Doel: "-", Effect: e.naam, "Rondes resterend": e.resterendeRondes });
}
if (!rijen.length) {
    rijen = [{ Niveau: "-", Doel: "-", Effect: "geen actieve effecten", "Rondes resterend": "-" }];
}
msg.payload = rijen;
return msg;

// Sync de toestand-LEDs en publiceer de toestanden/portalen voor de simulator.
// out1 -> pof/toestanden | out2 -> pof/portalen | out3 -> commando/master1 (LED per paal)
const bord = global.get("bordStaat") || {};

// 1) Toestanden-lijst: per actief uur-effect een rij (voor het sim-"Toestanden"-paneel).
const toestanden = [];
for (const u in bord) {
    for (const e of (bord[u].effecten || [])) {
        toestanden.push({ uur: parseInt(u, 10), effect: e.effect, naam: e.naam, resterendeRondes: e.resterendeRondes });
    }
}

// 2) Portaal-paren (voor de paarse verbindingslijn in de simulator).
const seen = {};
const paren = [];
for (const u in bord) {
    for (const e of (bord[u].effecten || [])) {
        if (e.effect !== "portaal") continue;
        const a = parseInt(u, 10);
        const b = e.data && e.data.partner;
        if (b == null) continue;
        for (const pb of (Array.isArray(b) ? b : [b])) {
            const key = a < pb ? a + "-" + pb : pb + "-" + a;
            if (seen[key]) continue;
            seen[key] = true;
            paren.push({ palen: [a, pb] });
        }
    }
}

// 3) LED per paal volgt rechtstreeks uit de actieve toestand: portaal -> paars (1),
// happy_hour -> goud (2), anders uit (0). Stuur enkel bij wijziging; zo gaan verlopen
// of gestopte toestanden vanzelf weer uit (fixt de "stale" paarse palen).
const ACTIE = { portaal: 1, happy_hour: 2, medicijn: 4 };
const palenRing = (global.get("palenActief") || global.get("paaltjesLijst") || []).slice();
const nukeActief = global.get("nukeActief") === true;
const oogstMoment = global.get("middernachtOogst") === true;
const mnPaal = global.get("middernachtPaal") || (palenRing.length ? Math.max.apply(null, palenRing) : null);
const gewenst = {};
if (oogstMoment) {
    // Dramatische oogst-animatie over de HELE ring (actie 11).
    for (const u of palenRing) gewenst[u] = 11;
} else if (nukeActief) {
    // NUKE-ring: hele arena nucleair (actie 8).
    for (const u of palenRing) gewenst[u] = 8;
} else {
    for (const u in bord) {
        let actie = 0;
        for (const e of (bord[u].effecten || [])) { if (ACTIE[e.effect] !== undefined) { actie = ACTIE[e.effect]; break; } }
        if (actie) gewenst[u] = actie;
    }
    // Middernacht-poort op de middernacht-paal: wit (open) / rood (dicht), tenzij daar al een effect ligt.
    if (global.get("middernachtActief") === true && mnPaal != null && gewenst[mnPaal] === undefined) {
        gewenst[mnPaal] = (global.get("midnightOpen") === false) ? 10 : 9;
    }
}
// Volledige re-send forceren (na nuke/oogst-overgang) zodat geen paal op een oude kleur blijft hangen.
// We vullen 'vorige' met een sentinel (-1) voor ELKE ring-paal i.p.v. te legen: anders zou de uitzet-lus
// over een lege map lopen en bleef de nuke-/oogst-animatie (actie 8/11) hangen omdat er nooit actie 0 ging.
let vorige = global.get("paalLedActie") || {};
if (global.get("paalLedForceRebuild") === true) {
    vorige = {}; for (const u of palenRing) vorige[u] = -1;
    global.set("paalLedForceRebuild", false);
}
const cmds = [];
for (const u in gewenst) { if (vorige[u] !== gewenst[u]) cmds.push({ payload: { paal: parseInt(u, 10), actie: gewenst[u] } }); }
for (const u in vorige) { if (gewenst[u] === undefined) cmds.push({ payload: { paal: parseInt(u, 10), actie: 0 } }); }
global.set("paalLedActie", gewenst);

return [
    { topic: "pof/toestanden", payload: toestanden },
    { topic: "pof/portalen", payload: paren },
    cmds.length ? cmds : null
];

const we = global.get("wereldEffecten") || [];
let rijen = we.map(e => ({ Effect: e.naam, "Rondes resterend": e.resterendeRondes }));
if (!rijen.length) rijen = [{ Effect: "geen actieve wereld-effecten", "Rondes resterend": "-" }];
msg.payload = rijen;
return msg;

// Wis alle blijvende effecten (handig bij testen / herstart van een cyclus).
global.set("bordStaat", {});
global.set("spelerEffecten", {});
global.set("wereldEffecten", []);
msg.payload = "rebuild";
return msg;

// Controle: scoort op basis van het OPGENOMEN PAD (geordende hops), actie per actie.
// STAP = 1 levensuur (nooit achteruit); TELEPORT (tussen twee actieve portaal-palen) =
// 0 stappen, geen richtingcheck. Geen netto begin/eind-vergelijking.
const v = global.get("pofVerificatie") || {};
const loc = global.get("spelerLocaties") || {};
const se = global.get("spelerEffecten") || {};
const we = global.get("wereldEffecten") || [];
const bord = global.get("bordStaat") || {};
const ziek = global.get("ziekeSpelers") || {};
const dienaars = global.get("dienaars") || {};
const mnDicht = global.get("middernachtActief") === true && global.get("midnightOpen") === false;
const mnPaal = global.get("middernachtPaal");
const pad = global.get("pofPad") || {};
let stats = global.get("spelerStats") || {};
const palen = (global.get("palenActief") || global.get("paaltjesLijst") || []).slice().sort((a, b) => a - b);
const N = palen.length;
const idx = (p) => palen.indexOf(p);

function portaalPartner(p) {
    const fx = ((bord[p] || {}).effecten || []).find(e => e.effect === "portaal" && e.data && e.data.partner != null);
    return fx ? fx.data.partner : null;
}

// Ontleed het pad van een speler -> voorwaartse/achterwaartse stappen, teleports, geldigheid.
function ontleed(hops) {
    let voor = 0, achter = 0, ongeldig = false, bewogen = false, kruist = false;
    const portaalGebruik = {};
    for (const h of (hops || [])) {
        bewogen = true;
        const van = h[0], naar = h[1];
        if (portaalPartner(van) === naar) {            // TELEPORT
            const key = van < naar ? van + "-" + naar : naar + "-" + van;
            portaalGebruik[key] = (portaalGebruik[key] || 0) + 1;
            if (portaalGebruik[key] > 1) ongeldig = true;   // max 1x per portaal per zet
            continue;
        }
        const iv = idx(van), inr = idx(naar);
        if (N < 2 || iv < 0 || inr < 0) continue;
        const fd = (((inr - iv) % N) + N) % N;
        const bd = N - fd;
        if (fd <= bd) { voor += fd; if (inr < iv) kruist = true; } else achter += bd;   // forward-wrap = oversteek middernacht
    }
    return { voor, achter, ongeldig, bewogen, kruist };
}

const doelwitSet = new Set(v.doelwit || []);
const start = v.startPosities || {};
const voorwaarde = v.voorwaarde || "geen";
const x = v.getal;
const y = v.getal2;
const bewegingEvent = (voorwaarde === "min" || voorwaarde === "max" || voorwaarde === "of");

// NUKE (wereld-event): geen bewegings-straffen — iedereen mocht vluchten. Wie bij de controle nog
// gedetecteerd is (in spelerLocaties) zat binnen het bereik en ONTPLOFT (uren 0 + sterfte); wie
// ontkomen is (onder de RSSI-vloer / buiten het veld, dus weg uit spelerLocaties) is VEILIG.
const _huidig = global.get("pofHuidigEvent") || {};
if ((_huidig.gevolgen || []).some(g => g.type === "nuke")) {
    let nrijen = [];
    for (const naam in start) {
        let s = stats[naam] || {}; if (s.totaalUren === undefined) s.totaalUren = 0; if (s.sterftes === undefined) s.sterftes = 0;
        const gedetecteerd = loc[naam] != null;
        let st;
        if (gedetecteerd) { s.totaalUren = 0; s.sterftes += 1; st = "ONTPLOFT"; }
        else st = "VEILIG (ontkomen)";
        stats[naam] = s;
        nrijen.push({ Speler: naam, Tag: "-", Verplaatst: gedetecteerd ? "in zone" : "uit zone", Status: st, _status: st, _delta: gedetecteerd ? "-alles" : 0 });
    }
    global.set("spelerStats", stats);
    global.set("pofPad", {});
    // Een nuke wist de wereld: ruim ook de ziekte-episode (zieken + medicijnen) en dienaars op.
    // 'Ziekte-beheer' (via output 1) herpubliceert daarna lege pof/ziekte + pof/dienaars en herstelt de LEDs.
    global.set("ziekeSpelers", {});
    global.set("dienaars", {});
    for (const _u in bord) { const _fx = ((bord[_u].effecten) || []).filter(e => e.effect !== "medicijn"); if (_fx.length) bord[_u].effecten = _fx; else delete bord[_u]; }
    global.set("bordStaat", bord);
    global.set("nukeActief", false); global.set("paalLedForceRebuild", true);   // ring weg, LEDs herstellen
    // Regroup-fase i.p.v. de normale aanloop.
    global.set("pofFase", "regroup");
    global.set("pofTeller", _huidig.regroup_s || 60);
    const nctrl = { topic: "pof/controle", payload: { event: "Nuke", resultaten: nrijen.map(r => ({ speler: r.Speler, status: r._status, verplaatst: r.Verplaatst, delta: r._delta, tag: "-" })) } };
    const ntabel = nrijen.map(r => ({ Speler: r.Speler, Tag: r.Tag, Verplaatst: r.Verplaatst, Status: r.Status }));
    global.set("pofLaatsteControle", ntabel);
    msg.payload = ntabel.length ? ntabel : [{ Speler:"-", Tag:"-", Verplaatst:"-", Status:"geen spelers" }];
    return [msg, nctrl];
}

let rijen = [];
let genezen = [];
for (const naam in start) {
    let s = stats[naam] || {};
    if (s.totaalUren === undefined) s.totaalUren = 0;
    if (s.sterftes === undefined) s.sterftes = 0;
    if (s.tijdTerug === undefined) s.tijdTerug = false;

    const heeftBlok = (se[naam] || []).some(e => e.effect === "mag_niet_bewegen");
    const r = ontleed(pad[naam]);
    const isDoel = bewegingEvent && doelwitSet.has(naam);
    let status, delta = 0;

    if (heeftBlok) { status = "GEBLOKKEERD"; delta = 0; }
    else if (isDoel) {
        if (r.ongeldig) { status = "ONGELDIGE TELEPORT"; delta = -r.voor; }
        else if (r.achter > 0) { status = "TERUG IN TIJD"; delta = -r.achter; }
        else if (voorwaarde === "max" && r.voor > x) { status = "TE VEEL"; delta = -(r.voor - x); }
        else if (voorwaarde === "min" && r.voor < x) { status = "TE WEINIG"; delta = -r.voor; }
        else if (voorwaarde === "of" && r.voor !== x && r.voor !== y) { status = "ONGELDIGE KEUZE"; delta = -r.voor; }
        else { status = "OK"; delta = r.voor; }
    } else {
        // Niet-(bewegings)doelwit: moet stil blijven staan.
        if (!r.bewogen && !r.ongeldig) { status = "OK (stil)"; delta = 0; }
        else { status = "BEWOOG (mocht niet)"; delta = -(r.voor + r.achter); }
    }

    // Middernacht-poort dicht: een speler die OP de middernacht-paal staat mag niet bewegen.
    if (mnDicht && start[naam] === mnPaal && r.bewogen) { status = "MIDDERNACHT DICHT"; delta = -r.voor; }

    // Ziekte-modifier: zieke speler loopt door de NORMALE controle (geen vrijstelling). Hij verdient
    // geen levensuren (winst -> 0), maar verliest wel bij onwettige zetten. Genezen kan ENKEL als de zet
    // legaal was (OK / OK (stil)) en hij op een medicijn-uur eindigt.
    if (ziek[naam] != null) {
        if (delta > 0) delta = 0;
        const legaal = (status === "OK" || status === "OK (stil)");
        const opMed = ((bord[loc[naam]] || {}).effecten || []).some(e => e.effect === "medicijn");
        if (legaal && opMed) { status = "GENEZEN"; genezen.push({ naam: naam, uur: loc[naam] }); }
        else if (legaal) { status = "ZIEK"; }
    }

    // Happy hour x2 op een LEGAAL verdiende beloning (eindpaal heeft happy_hour).
    if (delta > 0) {
        const happy = ((bord[loc[naam]] || {}).effecten || []).some(e => e.effect === "happy_hour");
        if (happy) { delta *= 2; status += " (happy hour x2)"; }
    }
    // Toepassen + sterfte. Een DIENAAR verdient niets voor zichzelf: positieve winst gaat naar de meester
    // (die kan ze niet meer verliezen); verlies + sterfte blijven wel bij de dienaar.
    const meester = dienaars[naam];
    if (meester != null && delta > 0) {
        let m = stats[meester] || {}; if (m.totaalUren===undefined) m.totaalUren=0; if (m.sterftes===undefined) m.sterftes=0;
        m.totaalUren += delta; stats[meester] = m;
        status += " -> dient " + meester + " (+" + delta + ")";
    } else {
        const nieuw = s.totaalUren + delta;
        if (nieuw < 0) { s.totaalUren = 0; s.sterftes += 1; status += " -> STERFTE"; }
        else s.totaalUren = nieuw;
    }
    stats[naam] = s;

    const paalFX = ((bord[loc[naam]] || {}).effecten || []).map(e => e.naam);
    const allFX = [...(se[naam] || []).map(e => e.naam), ...we.map(e => e.naam), ...paalFX];
    const tag = allFX.length ? allFX.join(", ") : "-";
    const dStr = (delta >= 0 ? "+" : "") + delta;
    rijen.push({ Speler: naam, Tag: tag, Verplaatst: (r.voor - r.achter), Status: status + " (" + dStr + " uur)", _status: status, _delta: delta });
}
global.set("spelerStats", stats);
global.set("pofGenezen", genezen);

const manueel = global.get("pofManueel") === true;
global.set("pofFase", manueel ? "wacht" : "aanloop");
global.set("pofTeller", manueel ? 0 : 5);
global.set("pofPad", {});

const FOUT = new Set(["TERUG IN TIJD", "TE VEEL", "TE WEINIG", "ONGELDIGE KEUZE", "BEWOOG (mocht niet)", "ONGELDIGE TELEPORT"]);
const controleMsg = {
    topic: "pof/controle",
    payload: {
        event: (global.get("pofHuidigEvent") || {}).naam || "",
        resultaten: rijen.map(r => ({ speler: r.Speler, status: FOUT.has(r._status) ? r._status : "OK", verplaatst: r.Verplaatst, delta: r._delta, tag: r.Tag }))
    }
};
const tabel = rijen.map(r => ({ Speler: r.Speler, Tag: r.Tag, Verplaatst: r.Verplaatst, Status: r.Status }));
global.set("pofLaatsteControle", tabel);
msg.payload = tabel.length ? tabel : [{ Speler:"-", Tag:"-", Verplaatst:"-", Status:"geen spelers" }];
return [msg, controleMsg];

const spelersLijst = global.get("spelersLijst") || {};
const gp = global.get("gespauzeerdePlayers") || {};
msg.payload = Object.values(spelersLijst).map(naam => ({
    naam: naam,
    gepauzeerd: gp[naam] === true
}));
return msg;

if (!msg.payload || !msg.payload.speler) return null;
const gp = global.get("gespauzeerdePlayers") || {};
gp[msg.payload.speler] = msg.payload.gepauzeerd;
global.set("gespauzeerdePlayers", gp);
const spelersLijst = global.get("spelersLijst") || {};
msg.payload = Object.values(spelersLijst).map(naam => ({
    naam: naam,
    gepauzeerd: gp[naam] === true
}));
return msg;

const bevestigd = global.get("stop_bevestigd") === true;
if (!bevestigd) {
    msg.payload = "GEBLOKKEERD - zet eerst 'Bevestig stop' aan (stap 1).";
    return [msg, null];
}
global.set("spelToestand", "gestopt");
global.set("pofActief", false);
global.set("pofFase", "idle");
global.set("stop_bevestigd", false);
// Historiek: bundel het huidige spel en bewaar in de historiek
const _afgerond = global.get("pofHuidigSpel");
if (_afgerond && _afgerond.events.length) {
    _afgerond.eind = new Date().toISOString();
    let _hist = global.get("spelHistorie") || [];
    _hist.unshift(_afgerond);
    global.set("spelHistorie", _hist);
}
global.set("pofHuidigSpel", null);
global.set("pofHuidigEvent", null);
global.set("pofWachtrij", []);
global.set("pofEventenRonde", 0);
global.set("pofDoelwitReveal", "");
global.set("bordStaat", {});
global.set("spelerEffecten", {});
global.set("wereldEffecten", []);
global.set("pofVerificatie", {});
global.set("pofLaatsteControle", []);
// GLOBALE stats (levensdagen/levensuren/sterftes/skills) blijven bewaard.
msg.payload = "Spel GESTOPT. Globale stats blijven bewaard ([BEHEER] Wis globale stats wist ze).";
return [msg, { payload: false }, { payload: "Gestopt" }, { payload: "Events deze ronde: 0" }, { payload: "—" }, { payload: "rebuild" }];

const actief = global.get("pofActief") === true;
const fase   = global.get("pofFase") || "idle";
const event  = global.get("pofHuidigEvent") || {};
const teller = global.get("pofTeller") ?? null;
const maxT   = global.get("pofTellerMax") ?? null;
const ver    = global.get("pofVerificatie") || {};
const reveal = global.get("pofDoelwitReveal") || "";

// Wachtrij: plan tot 5 volgende kiesbare events vooruit (voor de simulator-preview).
const lopend = (global.get("spelToestand") || "gestopt") === "lopend";
let wachtrij = global.get("pofWachtrij") || [];
let wachtrijNamen = [];
if (actief && lopend) {
    const evs = global.get("pofEvents") || [];
    const uitg = new Set(global.get("uitgeslotenEvents") || []);
    const inst = (id) => { const s = new Set(); const bord = global.get("bordStaat") || {}; for (const u in bord) for (const e of (bord[u].effecten || [])) if (e.bron === id) s.add(e.instId); const se = global.get("spelerEffecten") || {}; for (const n in se) for (const e of se[n]) if (e.bron === id) s.add(e.instId); for (const e of (global.get("wereldEffecten") || [])) if (e.bron === id) s.add(e.instId); return s.size; };
    const kiesbaar = evs.filter(e => !uitg.has(e.id) && (e.max == null || inst(e.id) < e.max));
    const kiesbaarIds = new Set(kiesbaar.map(e => e.id));
    wachtrij = wachtrij.filter(id => kiesbaarIds.has(id));
    while (wachtrij.length < 5 && kiesbaar.length) wachtrij.push(kiesbaar[Math.floor(Math.random() * kiesbaar.length)].id);
    const naamVan = {}; for (const e of evs) naamVan[e.id] = e.naam || e.id;
    wachtrijNamen = wachtrij.map(id => ({ id, naam: naamVan[id] || id }));
} else { wachtrij = []; }
global.set("pofWachtrij", wachtrij);

msg.payload = {
    actief,
    fase,
    eventNaam:   event.naam || "",
    eventTekst:  event.tekstIngevuld || "",
    doelwit:     ver.doelwit || [],
    doelwitType: (event.doelwit && event.doelwit.type) || "geen",
    groepLabel: (ver.groepVeld ? ver.groepVeld + ": " + ver.groepWaarde : null),
    doelwitReveal: reveal,
    getalWaarde: event.getalWaarde ?? null,
    getalWaarde2: event.getalWaarde2 ?? null,
    eventenRonde: global.get("pofEventenRonde") || 0,
    teller,
    maxTeller: maxT,
    wachtrij: wachtrijNamen
};
msg.topic = "pof/status";
return msg;

// Onthul de doelwitten een-voor-een (dashboard + global voor simulator).
// out1 -> Doelwit ui_text | out2 -> Voer gevolg uit | out3 -> Controle-tabel | out4 -> commando/master1 (buzzer-piep per uur)
const doelwit = msg.doelwit || [];
const _groep = msg.event && msg.event.doelwit && msg.event.doelwit.type === "groep";
const namen = _groep ? ["Groep " + (msg.groepLabel || "?")] : (doelwit.length ? doelwit : ["(niemand)"]);
const STAP = 1200;
const uurType = msg.event && msg.event.doelwit && msg.event.doelwit.type === "uur";
let lijnen = [];
global.set("pofDoelwitReveal", "");

const spelersLijst = global.get("spelersLijst") || {};
const loc = global.get("spelerLocaties") || {};
const se = global.get("spelerEffecten") || {};
const we = global.get("wereldEffecten") || [];
const bord = global.get("bordStaat") || {};
const doelSet = new Set(doelwit);
let beginRijen = [];
for (const mac in spelersLijst) {
    const naam = spelersLijst[mac];
    const paalFX = ((bord[loc[naam]] || {}).effecten || []).map(e => e.naam);
    const allFX = [...(se[naam] || []).map(e => e.naam), ...we.map(e => e.naam), ...paalFX];
    beginRijen.push({ Speler: naam, Tag: allFX.length ? allFX.join(", ") : "-", Verplaatst: 0, Status: doelSet.has(naam) ? "afwachten..." : "-" });
}
if (!beginRijen.length) beginRijen = [{ Speler:"-", Tag:"-", Verplaatst:"-", Status:"afwachten..." }];

namen.forEach((naam, i) => {
    setTimeout(() => {
        lijnen.push("- " + naam);
        const tekst = lijnen.join("\n");
        global.set("pofDoelwitReveal", tekst);
        const buzz = uurType ? { payload: { paal: naam, actie: 3 } } : null;
        node.send([{ payload: tekst }, null, null, buzz]);
    }, i * STAP);
});
setTimeout(() => { node.send([null, msg, null, null]); }, namen.length * STAP + 600);
return [null, null, { payload: beginRijen }, null];

let P = global.get("locParams");
if (!P) { P = { vensterMs:6000, hystereseDbm:6, rssiVloer:-92, graceMs:4000, switchSamples:2, minSamples:2 }; global.set("locParams", P); }
return [ {payload:P.vensterMs}, {payload:P.hystereseDbm}, {payload:P.rssiVloer}, {payload:P.graceMs}, {payload:P.switchSamples}, {payload:P.minSamples} ];

let P = global.get("locParams") || {};
const map = { venster:"vensterMs", hysterese:"hystereseDbm", vloer:"rssiVloer", grace:"graceMs", switch:"switchSamples", minsamp:"minSamples" };
const k = map[msg.topic];
if (k) { P[k] = Number(msg.payload); global.set("locParams", P); }
msg.payload = "Actief: " + JSON.stringify(global.get("locParams"));
return msg;

// Verzamel per beacon-MAC ruwe RSSI-samples voor stabiliteitsanalyse.
const d = msg.payload;
if (!d || d.mac === undefined || d.rssi === undefined) return null; // batterij-regels overslaan
const nu = Date.now();
let buf = global.get("beaconBuf") || {};
(buf[d.mac] = buf[d.mac] || []).push({ rssi: d.rssi, ts: nu, paal: d.paal });
if (buf[d.mac].length > 400) buf[d.mac] = buf[d.mac].slice(-400);
global.set("beaconBuf", buf);
return null;

const nu = Date.now();
const VENSTER = 15000;
let buf = global.get("beaconBuf") || {};
const spelers = global.get("spelersLijst") || {};
const kal = global.get("beaconKalibratie") || {};
let rows = [], lijst = [];
for (const mac in buf) {
    let arr = buf[mac].filter(x => nu - x.ts <= VENSTER);
    buf[mac] = arr;
    if (!arr.length) { delete buf[mac]; continue; }
    const n = arr.length;
    const dur = Math.max(1, (nu - arr[0].ts) / 1000);
    const rate = n / dur;
    const mean = arr.reduce((a,b)=>a+b.rssi,0)/n;
    const sd = Math.sqrt(arr.reduce((a,b)=>a+Math.pow(b.rssi-mean,2),0)/n);
    let maxGap = 0;
    for (let i=1;i<arr.length;i++) maxGap = Math.max(maxGap, arr[i].ts-arr[i-1].ts);
    const palen = new Set(arr.map(x=>x.paal)).size;
    let score = 100 - sd*4 - Math.max(0,maxGap-1500)/40 - Math.max(0,3-rate)*15;
    score = Math.max(0, Math.min(100, Math.round(score)));
    let advies = "OK";
    if (rate < 1.2) advies = "adv-interval verlagen (300 ms)";
    else if (maxGap > 4000) advies = "mist advertenties - batterij/positie";
    else if (sd > 8) advies = "plaatsing/antenne/tx-power";
    const naam = spelers[mac] || "(onbekend)";
    rows.push({ Beacon: naam, MAC: mac, Rate: rate.toFixed(1), "RSSI sigma": sd.toFixed(1), MaxGap: Math.round(maxGap)+"ms", Palen: palen, Score: score, Offset: (kal[mac]||0)+" dB", Advies: advies });
    lijst.push({ mac, naam, offset: kal[mac]||0, score });
}
global.set("beaconBuf", buf);
rows.sort((a,b)=>a.Score-b.Score);
lijst.sort((a,b)=>a.score-b.score);
return [{ payload: rows }, { payload: lijst }];

if (!msg.payload || !msg.payload.mac) return null;
let K = global.get("beaconKalibratie") || {};
K[msg.payload.mac] = Number(msg.payload.offset) || 0;
global.set("beaconKalibratie", K);
return null;

const loc = global.get("spelerLocaties") || {};
const spel = global.get("pofHuidigSpel") || null;
return [
  { topic: "locatie/spelers", payload: loc },
  { topic: "spel/historie", payload: spel ? { actief: true, start: spel.start, events: spel.events } : { actief: false, events: [] } }
];

const hist = global.get("spelHistorie") || [];
const fmt = (iso) => { try { return new Date(iso).toLocaleString("nl-BE"); } catch(e){ return iso; } };
msg.payload = hist.map(s => ({
  id: s.id,
  start: fmt(s.start),
  aantal: s.events.length,
  events: s.events.map(e => ({ nr: e.nr, tekst: e.tekst, doelwit: e.doelwit || [], getalWaarde: e.getalWaarde }))
}));
