if (global.get("simVeld24") !== true) return null;   // alleen actief in sim-modus
const lijst = msg.payload || [];
const spelers = global.get("spelersLijst") || {};
const vorige = global.get("spelerLocaties") || {};
let nieuw = {}, actief = [], bewegingen = [];
const nu = Date.now();
let seenMac = global.get("status_lastSeenMac") || {};
let seenPaal = global.get("status_lastSeenPaal") || {};
for (const d of lijst) {
    const naam = spelers[d.mac]; if (!naam) continue;
    nieuw[naam] = d.paal; actief.push(naam);
    if (vorige[naam] !== d.paal) bewegingen.push({ payload: { speler: naam, vanPaal: (vorige[naam] !== undefined ? vorige[naam] : d.paal), naarPaal: d.paal } });
