global.set("status_lastSeenPaal", seenPaal);
global.set("status_lastDataTs", nu);
return [ null, bewegingen.length ? bewegingen : null ];

const sim = global.get("simVeld24") === true;
const lopend = (global.get("spelToestand")||"gestopt") === "lopend";
if (!sim && lopend) return null;   // tijdens echt spel laat de locatie-functie de radar lopen
const spelers = global.get("spelersLijst")||{};
const loc = global.get("spelerLocaties")||{};
const stats = global.get("spelerStats")||{};
let rows=[];
for (const mac in spelers){
    const n = spelers[mac];
    if (sim && !(n in loc)) continue;
    const t = (stats[n] && stats[n].totaalUren) || 0;
    rows.push({ Speler:n, Locatie: (loc[n]!=null?"Paal "+loc[n]:"-"), RSSI:"-", Levensdagen: Math.floor(t/24), Levensuren: t%24, Sterftes: (stats[n] && stats[n].sterftes)||0 });
}
