const ev = global.get("pofHuidigEvent") || {};
const fase = global.get("pofFase") || "idle";
const teller = global.get("pofTeller");
const reveal = global.get("pofDoelwitReveal") || "—";
const controle = global.get("pofLaatsteControle") || [];
