const eventTekst = ev.naam ? (ev.naam + (ev.tekstIngevuld ? " — " + ev.tekstIngevuld : "")) : "—";
const timerTekst = ((fase === "reactie" || fase === "aanloop") && teller != null) ? (fase + ": " + teller + "s") : fase;
let radar = [];
for (const mac in spelers){ const n=spelers[mac]; if(!(n in loc)) continue; const t=(stats[n]&&stats[n].totaalUren)||0;
  radar.push({ Speler:n, Locatie:"Paal "+loc[n], Levensdagen:Math.floor(t/24), Levensuren:t%24, Sterftes:(stats[n]&&stats[n].sterftes)||0 }); }
if (!radar.length) radar=[{ Speler:"-", Locatie:"-", Levensdagen:0, Levensuren:0, Achterstand:0 }];
return [ {payload:eventTekst}, {payload:reveal}, {payload:timerTekst}, {payload: controle.length?controle:[{Speler:"-",Status:"-"}]}, {payload:radar}, {payload: "Spel: " + toestand.toUpperCase() + "  |  POF: " + fase} ];

// Bouw de globale-stats-tabel (blijft over Stop heen; wis met [BEHEER] Wis globale stats).
