}
if (!rows.length) rows=[{ Speler:"-", Levensdagen:0, Levensuren:0, Skills:"-", Sterftes:0 }];
msg.payload = rows;
return msg;

// Bouw de globale-stats-tabel (blijft over Stop heen; wis met [BEHEER] Wis globale stats).
const spelers = global.get("spelersLijst")||{};
const stats = global.get("spelerStats")||{};
let rows=[];
for (const mac in spelers){
    const n = spelers[mac];
    const s = stats[n]||{};
    const t = s.totaalUren||0;
    const sk = (s.skills && s.skills.length) ? s.skills.join(", ") : "-";
