// Eén schakelaar voor start/stop van spel + POF, en wist meteen alle paal-LEDs
// (defensief: stale LED's van verwijderde/oude events gaan zo altijd uit).
const aan = (msg.payload === true || msg.payload === "aan" || msg.payload === "start");
const manueel = global.get("pofManueel") === true;
function resetSpelStaat() {
    const _af = global.get("pofHuidigSpel");
    if (_af && _af.events && _af.events.length) { _af.eind = new Date().toISOString(); const _h = global.get("spelHistorie") || []; _h.unshift(_af); global.set("spelHistorie", _h); }
    global.set("pofHuidigSpel", null); global.set("pofHuidigEvent", null); global.set("pofWachtrij", []);
    global.set("pofActief", false); global.set("pofFase", "idle"); global.set("pofTeller", 0);
    global.set("pofEventenRonde", 0); global.set("pofDoelwitReveal", "");
    global.set("bordStaat", {}); global.set("spelerEffecten", {}); global.set("wereldEffecten", []);
    global.set("pofVerificatie", {}); global.set("pofLaatsteControle", []); global.set("pofPad", {});
}
let melding;
if (aan) {
    resetSpelStaat();
    global.set("spelToestand", "lopend"); global.set("pofActief", true); global.set("pofEventenRonde", 0);
    global.set("pofHuidigSpel", { id: Date.now(), start: new Date().toISOString(), events: [] });
    if (manueel) { global.set("pofFase", "wacht"); global.set("pofTeller", 0); }
    else { global.set("pofFase", "aanloop"); global.set("pofTeller", 5); }
    melding = "LOOPT";
} else {
    resetSpelStaat(); global.set("spelToestand", "gestopt"); melding = "GESTOPT";
}
const palen = (global.get("palenActief") || global.get("paaltjesLijst") || []);
const cmds = palen.map(p => ({ payload: { paal: p, actie: 0 } }));
global.set("paalLedActie", {});
return [ { payload: "Toestand: " + melding }, cmds.length ? cmds : null ];

// Ziekte-lifecycle na de controle (draait elke ronde): genezen, dubbel-genezing,
// aftellen, sterfte, hartslag-waarschuwing en opschoning van medicijnen.
// out1 -> commando/master1 (zoemer-waarschuwing) | out2 -> pof/ziekte | out3 -> rebuild LEDs/tabel
let ziek = global.get("ziekeSpelers") || {};
const loc = global.get("spelerLocaties") || {};
let bord = global.get("bordStaat") || {};
let stats = global.get("spelerStats") || {};
function isMedicijnUur(u){ return (((bord[u]||{}).effecten)||[]).some(e=>e.effect==="medicijn"); }

// 1) Genezen: enkel spelers die in 'Verifieer beweging' WETTELIJK op een medicijn-uur eindigden
// (lijst pofGenezen). Tel cures per uur voor de dubbel-genezing.
const teGenezen = global.get("pofGenezen") || [];
const cureCount = {};
for (const g of teGenezen) {
    if (ziek[g.naam] == null) continue;
    delete ziek[g.naam];
    if (g.uur != null) cureCount[g.uur] = (cureCount[g.uur] || 0) + 1;
}
global.set("pofGenezen", []);

// 2) Dubbel-genezing: een medicijn-uur waar >=2 zieken samen genazen, wordt verbruikt.
for (const u in cureCount) {
    if (cureCount[u] >= 2 && bord[u]) bord[u].effecten = (bord[u].effecten||[]).filter(e=>e.effect!=="medicijn");
}

// 3) Resterende zieken: aftellen; bij 0 sterven (uren 0 + sterfte), anders bij <=3 waarschuwen.
let cmds = [];
for (const naam in ziek) {
    let over = ziek[naam] - 1;
    if (over <= 0) {
        let s = stats[naam] || {}; if (s.totaalUren===undefined) s.totaalUren=0; if (s.sterftes===undefined) s.sterftes=0;
        s.totaalUren = 0; s.sterftes += 1; stats[naam] = s;
        delete ziek[naam];
        node.warn("Ziekte: " + naam + " is gestorven (geen medicijn op tijd)");
    } else {
        ziek[naam] = over;
        if (over <= 3) { const actie = over===3?5:(over===2?6:7); const u = loc[naam]; if (u != null) cmds.push({ payload: { paal: u, actie: actie } }); }
    }
}

// 4) Opschonen: geen zieken meer -> alle medicijnen weg (episode voorbij).
if (Object.keys(ziek).length === 0) {
    for (const u in bord) bord[u].effecten = ((bord[u].effecten)||[]).filter(e=>e.effect!=="medicijn");
}
for (const u in bord) { if (!(((bord[u]||{}).effecten)||[]).length) delete bord[u]; }

global.set("ziekeSpelers", ziek);
global.set("spelerStats", stats);
global.set("bordStaat", bord);

const lijst = Object.keys(ziek).map(n => ({ speler:n, rondesOver: ziek[n], uur: loc[n] != null ? loc[n] : null }));
return [ cmds.length ? cmds : null, { topic:"pof/ziekte", payload: lijst }, { payload:"rebuild" }, { topic:"pof/dienaars", payload: global.get("dienaars") || {} } ];

// Bereken de eerste 500 cijfers van pi via Machin (BigInt) en zet global.piDigits.
const N = 500;
const SCALE = 10n ** BigInt(N + 12);
function arccot(x){ const xb=BigInt(x), x2=xb*xb; let xpow=SCALE/xb, sum=xpow, n=1n, sign=-1n; while(xpow>0n){ xpow=xpow/x2; const term=xpow/(2n*n+1n); sum+=sign*term; sign=-sign; n++; } return sum; }
const pi = 16n*arccot(5) - 4n*arccot(239);
const s = pi.toString();
global.set("piDigits", s.slice(0, N).split("").map(d=>parseInt(d,10)));
node.warn("Pi-cijfers berekend: " + s.slice(0,12) + "... (" + N + " cijfers)");
return null;

// Einde van de dramatische oogst-animatie: LED's herstellen naar normaal.
global.set("middernachtOogst", false);
global.set("paalLedForceRebuild", true);
return { payload: "oogst-einde" };

// MIDDERNACHT (één keer per event, getriggerd door 'Kies event'). De poort volgt de pi-cijfers:
// start open; elke fase duurt 'cijfer' events, dan flip open<->dicht. Een 0-cijfer = OOGST (geen flip).
// out1 -> commando/master1 (oogst-animatie) | out2 -> pof/middernacht | out3 -> pof/dienaars
// out4 -> Sync LEDs (poort-LED) | out5 -> Oogst-delay (herstel na de animatie)
// Uitgeschakeld via de simulator-checkbox: de hoogste paal is dan een NORMAAL uur (geen poort,
// geen oogst, geen oversteek-blokkade). De pi-stand wordt NIET aangeraakt zodat ze bij weer
// inschakelen verderloopt. Publiceer een lege poort-status en trigger een LED-sync (poort-LED weg).
if (global.get("middernachtAan") === false) {
    global.set("middernachtActief", false);
    return [null, { topic: "pof/middernacht", payload: null }, null, { payload: "sync" }, null];
}
const digits = global.get("piDigits") || [];
if (!digits.length) return null;
const palenRing = (global.get("palenActief") || global.get("paaltjesLijst") || []).slice();
const mnPaal = palenRing.length ? Math.max.apply(null, palenRing) : 24;
global.set("middernachtPaal", mnPaal);
global.set("middernachtActief", true);
const digitAt = (i) => digits[((i % digits.length) + digits.length) % digits.length];

let idx = global.get("midnightIndex"); if (idx == null) idx = 0;
let open = global.get("midnightOpen");
let rem = global.get("midnightRemaining");
let harvest = false;

if (rem == null) { open = true; rem = digitAt(0); idx = 1; }
else {
    rem = rem - 1;
    if (rem <= 0) {
        while (true) {
            const d = digitAt(idx); idx = idx + 1;
            if (d === 0) { harvest = true; continue; }   // 0 = oogst, geen flip
            open = !open; rem = d; break;
        }
    }
}
idx = ((idx % digits.length) + digits.length) % digits.length;
global.set("midnightIndex", idx);
global.set("midnightOpen", open);
global.set("midnightRemaining", rem);

let dienaars = global.get("dienaars") || {};
let cmds = null;
if (harvest) {
    let stats = global.get("spelerStats") || {};
    const loc = global.get("spelerLocaties") || {};
    const opMN = Object.keys(loc).filter(n => loc[n] === mnPaal);
    for (const naam of opMN) {
        let s = stats[naam] || {}; if (s.totaalUren===undefined) s.totaalUren=0; if (s.sterftes===undefined) s.sterftes=0;
        s.totaalUren = 0; s.sterftes += 1; stats[naam] = s;
        if (!dienaars[naam]) {
            const kand = Object.keys(loc).filter(m => opMN.indexOf(m) < 0 && !dienaars[m]);
            let meester = null, minU = Infinity;
            for (const m of kand) { const u = (stats[m] && stats[m].totaalUren) || 0; if (u < minU) { minU = u; meester = m; } }
            if (meester) dienaars[naam] = meester;
            node.warn("Middernacht-oogst: " + naam + " geoogst" + (meester ? " -> dient " + meester : " (geen meester)"));
        } else {
            node.warn("Middernacht-oogst: " + naam + " geoogst (was al dienaar van " + dienaars[naam] + ")");
        }
    }
    global.set("spelerStats", stats);
    global.set("dienaars", dienaars);
    global.set("middernachtOogst", true);
    global.set("paalLedForceRebuild", true);
    cmds = palenRing.map(u => ({ payload: { paal: u, actie: 11 } }));
}

function eventsTotOogst() {
    let i = idx, r = rem, count = 0, guard = 0;
    while (guard++ < 6000) {
        count++; r = r - 1;
        if (r <= 0) {
            while (true) {
                const d = digitAt(i); i = i + 1;
                if (d === 0) return count;
                r = d; break;
            }
        }
    }
    return null;
}

const mn = { topic: "pof/middernacht", payload: { index: idx, open: open, remaining: rem, eventsTotOogst: eventsTotOogst(), paal: mnPaal } };
const dn = { topic: "pof/dienaars", payload: dienaars };
return [ cmds, mn, dn, { payload: "sync" }, harvest ? { payload: "oogst" } : null ];

const m = msg.payload || {};
msg.payload = (m.open ? "🟢 Poort OPEN" : "🔴 Poort DICHT") + "  |  nog " + (m.remaining!=null?m.remaining:"?") + " events in fase  |  oogst over " + (m.eventsTotOogst!=null?m.eventsTotOogst:"?") + " events  (pi-index " + (m.index!=null?m.index:"?") + ")";
return msg;

const d = msg.payload || {};
const rijen = Object.keys(d).map(n => ({ Dienaar: n, Meester: d[n] }));
msg.payload = rijen.length ? rijen : [{ Dienaar: "-", Meester: "-" }];
return msg;
